   151→router.get('/getFollowsData', async(req, res) => {
   152→    const {userId, loggedInUserId} = req.query;
   153→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
   154→    // console.log(req.query)
   155→    try {
   156→        const followersCountPromise = supabase
   157→        .from('follows')
   158→        .select('*', {count: 'exact', head: true})
   159→        .eq('following_id', userId);
   160→
   161→        const followingCountPromise = supabase
   162→        .from('follows')
   163→        .select('*', {count: 'exact', head: true})
   164→        .eq('follower_id', userId)
   165→
   166→        const isFollowingPromise = supabase
