   172→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
   173→            followersCountPromise, followingCountPromise, isFollowingPromise,
   174→        ])
   175→
   176→
   177→        const {count: followersCount, error: errorFollowers } = followersCountResult;
   178→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
   179→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
