   224→router.get('/getNotifications', async(req, res) =>{
   225→    const {before, limit} = req.query;
   226→
   227→    const token = req.headers?.authorization?.split(' ')[1];
   228→    if(!token){
   229→        console.error('not authorized')
   230→        return res.status(400).json({error:'not authorized'})
   231→    }
   232→
   233→    const {data: authData, error: errorAuthData} = await supabase.auth.getUser(token);
   234→
   235→    if(errorAuthData){
   236→        console.error('error:', errorAuthData.message);
   237→        return res.status(500).json({error: 'error on checking authorization'})
   238→    }
   239→
   240→    const userId = authData?.user?.id;
   241→
   242→    // Fetch a generous amount from both tables, then merge and paginate
   243→    const fetchLimit = parseInt(limit) + 1;
   244→
   245→    let journalQuery = supabase
   246→    .from('notifications')
   247→    .select(
   248→        `*,
   249→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
   250→        users!sender_id(name, user_email, image_url, id, badge)
   251→        `
   252→    )
   253→    .eq('receiver_id', userId)
   254→    .order('created_at', {ascending: false})
   255→    .order('id', {ascending: false})
   256→    .limit(fetchLimit)
   257→
   258→    let opinionQuery = supabase
   259→    .from('notification_opinions')
   260→    .select(
   261→        `*,
   262→        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
   263→        users!sender_id(name, user_email, image_url, id, badge)
   264→        `
   265→    )
   266→    .eq('receiver_id', userId)
   267→    .order('created_at', {ascending: false})
   268→    .order('id', {ascending: false})
   269→    .limit(fetchLimit)
   270→
   271→    if(before){
   272→        journalQuery = journalQuery.lt('created_at', before);
   273→        opinionQuery = opinionQuery.lt('created_at', before);
   274→    }
   275→
   276→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
   277→
   278→    if(journalResult.error){
   279→        console.error('error while fetching data from notification table:', journalResult.error);
   280→        return res.status(500).json({error: 'error fetching data from notification table'});
   281→    }
   282→    if(opinionResult.error){
   283→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
   284→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
   285→    }
   286→
   287→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
   288→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
   289→
   290→    // Merge and sort by created_at descending
   291→    const merged = [...journalNotifs, ...opinionNotifs]
   292→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
   293→
   294→    // Likes/bookmarks lookup only for journal notifications
   295→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
   296→
   297→    let hasLikedResult = [];
   298→    let hasBookMarkedResult = [];
   299→    if(journalIds.length > 0){
   300→        const [hasLiked, hasBookMarked] = await Promise.all([
   301→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
   302→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
   303→        ]);
   304→
   305→        if(hasLiked.error || hasBookMarked.error){
   306→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
   307→        }
   308→        hasLikedResult = hasLiked.data || [];
   309→        hasBookMarkedResult = hasBookMarked.data || [];
   310→    }
   311→
   312→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
   313→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
   314→
   315→    const formatted = merged.map((notif) => ({
   316→        ...notif,
   317→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
   318→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
   319→    }))
   320→
   321→    const hasMore = formatted.length > parseInt(limit);
   322→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
   323→
   324→    return res.status(200).json(
   325→        {
   326→            hasMore: hasMore,
   327→            data: slicedData,
   328→        }
   329→    )
   330→
   331→})
